class Solution:
    def search(self, nums: list[int], target: int) -> int:
        left, right = 0, len(nums) - 1
        while left <= right:
            mid = left + (right - left) // 2
            if nums[mid] == target:
                return mid
            elif nums[mid] < target:
                if nums[left] == nums[mid]:
                    left += 1
                else:
                    left = mid + 1
            else:
                if nums[right] == nums[mid]:
                    right -= 1
                else:
                    right = mid - 1
        return -1


